// webp
function testWebP(callback) {
   var webP = new Image();
   webP.onload = webP.onerror = function () {
      callback(webP.height == 2);
   };
   webP.src = 'data:image/webp;base64,UklGRjoAAABXRUJQVlA4IC4AAACyAgCdASoCAAIALmk0mk0iIiIiIgBoSygABc6WWgAA/veff/0PP8bA//LwYAAA';
}
testWebP(function (support) {
   if (support == true) {
      document.querySelector('body').classList.add('webp');
   } else {
      document.querySelector('body').classList.add('no-webp');
   }
});
// burger
function burgerMenu() {
   const burger = document.querySelector('.burger')
   const menu = document.querySelector('.nav__menu')
   const body = document.querySelector('body')
   const close = menu.querySelector('.close')
   burger.addEventListener('click', () => {
      if (!menu.classList.contains('active')) {
         menu.classList.add('active')
         burger.classList.add('active')
         body.classList.add('locked')
      } else {
         menu.classList.remove('active')
         burger.classList.remove('active')
         body.classList.remove('locked')
      }
   })
   close.addEventListener('click', () => {
      if (!menu.classList.contains('active')) {
         menu.classList.add('active')
         burger.classList.add('active')
         body.classList.add('locked')
      } else {
         menu.classList.remove('active')
         burger.classList.remove('active')
         body.classList.remove('locked')
      }

   })
   if (document.querySelector('body.menu')) {
      const menuBurger = document.querySelector('.menu__burger')
      const menuAside = document.querySelector('.menu__aside')
      const close2 = menuAside.querySelector('.close')
      menuBurger.addEventListener('click', () => {
         if (!menuAside.classList.contains('active')) {
            menuAside.classList.add('active')
            menuBurger.classList.add('active')
            body.classList.add('locked')
         } else {
            menuAside.classList.remove('active')
            menuBurger.classList.remove('active')
            body.classList.remove('locked')
         }
      })
      close2.addEventListener('click', () => {
         if (!menuAside.classList.contains('active')) {
            menuAside.classList.add('active')
            menuBurger.classList.add('active')
            body.classList.add('locked')
         } else {
            menuAside.classList.remove('active')
            menuBurger.classList.remove('active')
            body.classList.remove('locked')
         }
      })
   }
}
burgerMenu();
