if (document.querySelector('body.selector')) {
   var x, i, j, l, ll, selElmnt, a, b, c;
   x = document.getElementsByClassName('select');
   l = x.length;
   for (i = 0; i < l; i++) {
      selElmnt = x[i].getElementsByTagName('select')[0];
      ll = selElmnt.length;
      a = document.createElement('DIV');
      a.setAttribute('class', 'select-selected text');
      a.innerHTML = selElmnt.options[selElmnt.selectedIndex].innerHTML;
      x[i].appendChild(a);
      b = document.createElement('DIV');
      b.setAttribute('class', 'select-items select-hide text');
      for (j = 1; j < ll; j++) {
         c = document.createElement('DIV');
         c.innerHTML = selElmnt.options[j].innerHTML;
         c.addEventListener('click', function (e) {
            var y, i, k, s, h, sl, yl;
            s = this.parentNode.parentNode.getElementsByTagName('select')[0];
            sl = s.length;
            h = this.parentNode.previousSibling;
            for (i = 0; i < sl; i++) {
               if (s.options[i].innerHTML == this.innerHTML) {
                  s.selectedIndex = i;
                  h.innerHTML = this.innerHTML;
                  y = this.parentNode.getElementsByClassName('same-as-selected');
                  yl = y.length;
                  for (k = 0; k < yl; k++) {
                     y[k].removeAttribute('class');
                  }
                  this.setAttribute('class', 'same-as-selected text');
                  break;
               }
            }
            h.click();
         });
         b.appendChild(c);
      }
      x[i].appendChild(b);
      a.addEventListener('click', function (e) {
         e.stopPropagation();
         closeAllSelect(this);
         this.nextSibling.classList.toggle('select-hide');
         this.classList.toggle('select-arrow');
      });
   }
   function closeAllSelect(elmnt) {
      var x, y, i, xl, yl, arrNo = [];
      x = document.getElementsByClassName('select-items');
      y = document.getElementsByClassName('select-selected');
      xl = x.length;
      yl = y.length;
      for (i = 0; i < yl; i++) {
         if (elmnt == y[i]) {
            arrNo.push(i)
         } else {
            y[i].classList.remove('select-arrow');
         }
      }
      for (i = 0; i < xl; i++) {
         if (arrNo.indexOf(i)) {
            x[i].classList.add('select-hide');
         }
      }
   }
   document.addEventListener('click', closeAllSelect);
}
if (document.querySelector('body.range')) {
   //
   function controlFromInput(fromSlider, fromInput, toInput, controlSlider) {
      const [from, to] = getParsed(fromInput, toInput);
      fillSlider(fromInput, toInput, '#C2CFE0', '#21BB67', controlSlider);
      if (from > to) {
         fromSlider.value = to;
         fromInput.value = to;
      } else {
         fromSlider.value = from;
      }
   }
   function controlToInput(toSlider, fromInput, toInput, controlSlider) {
      const [from, to] = getParsed(fromInput, toInput);
      fillSlider(fromInput, toInput, '#C2CFE0', '#21BB67', controlSlider);
      setToggleAccessible(toInput);
      if (from <= to) {
         toSlider.value = to;
         toInput.value = to;
      } else {
         toInput.value = from;
      }
   }
   function controlFromSlider(fromSlider, toSlider, fromInput) {
      const [from, to] = getParsed(fromSlider, toSlider);
      fillSlider(fromSlider, toSlider, '#C2CFE0', '#21BB67', toSlider);
      if (from > to) {
         fromSlider.value = to;
         fromInput.value = to;
      } else {
         fromInput.value = from;
      }
   }
   function controlToSlider(fromSlider, toSlider, toInput) {
      const [from, to] = getParsed(fromSlider, toSlider);
      fillSlider(fromSlider, toSlider, '#C2CFE0', '#21BB67', toSlider);
      setToggleAccessible(toSlider);
      if (from <= to) {
         toSlider.value = to;
         toInput.value = to;
      } else {
         toInput.value = from;
         toSlider.value = from;
      }
   }
   function getParsed(currentFrom, currentTo) {
      const from = parseInt(currentFrom.value, 10);
      const to = parseInt(currentTo.value, 10);
      return [from, to];
   }
   function fillSlider(from, to, sliderColor, rangeColor, controlSlider) {
      const rangeDistance = to.max - to.min;
      const fromPosition = from.value - to.min;
      const toPosition = to.value - to.min;
      controlSlider.style.background = `linear-gradient(
        to right,
        ${sliderColor} 0%,
        ${sliderColor} ${(fromPosition) / (rangeDistance) * 100}%,
        ${rangeColor} ${((fromPosition) / (rangeDistance)) * 100}%,
        ${rangeColor} ${(toPosition) / (rangeDistance) * 100}%, 
        ${sliderColor} ${(toPosition) / (rangeDistance) * 100}%, 
        ${sliderColor} 100%)`;
   }
   function setToggleAccessible(currentTarget) {
      const toSlider = document.querySelector('#toSlider');
      if (Number(currentTarget.value) <= 0) {
         toSlider.style.zIndex = 2;
      } else {
         toSlider.style.zIndex = 0;
      }
   }
   const fromSlider = document.querySelector('#fromSlider');
   const toSlider = document.querySelector('#toSlider');
   const fromInput = document.querySelector('#fromInput');
   const toInput = document.querySelector('#toInput');
   fillSlider(fromSlider, toSlider, '#C2CFE0', '#21BB67', toSlider);
   setToggleAccessible(toSlider);
   fromSlider.oninput = () => controlFromSlider(fromSlider, toSlider, fromInput);
   toSlider.oninput = () => controlToSlider(fromSlider, toSlider, toInput);
   fromInput.oninput = () => controlFromInput(fromSlider, fromInput, toInput, toSlider);
   toInput.oninput = () => controlToInput(toSlider, fromInput, toInput, toSlider);
}
if (document.querySelector('body.accordion')) {
   // 
   function accordion() {
      const items = document.querySelectorAll('.accordion__header')
      items.forEach(item => {
         item.addEventListener('click', () => {
            const parent = item.parentNode
            if (parent.classList.contains('show')) {
               parent.classList.remove('show')
            } else {
               document
                  .querySelectorAll('.accordion__item')
                  .forEach(child => child.classList.remove('show'))
               parent.classList.add('show')
            }
         })
      })
   }
   accordion()
   //
   let dropArea = document.getElementById('holder');['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
      dropArea.addEventListener(eventName, preventDefaults, false)
   })
   function preventDefaults(e) {
      e.preventDefault()
      e.stopPropagation()
   }
   dropArea.addEventListener('drop', handleDrop, false)
   function handleDrop(e) {
      let dt = e.dataTransfer
      let files = dt.files

      handleFiles(files)
   }
   function handleFiles(files) {
      ([...files]).forEach(uploadFile)
   }
   function uploadFile(file) {
      var url = 'YOUR URL HERE'
      var xhr = new XMLHttpRequest()
      var formData = new FormData()
      xhr.open('POST', url, true)
      xhr.addEventListener('readystatechange', function (e) {
         if (xhr.readyState == 4 && xhr.status == 200) {
         }
         else if (xhr.readyState == 4 && xhr.status != 200) {
         }
      })
      formData.append('file', file)
      xhr.send(formData)
   }
   let forms = document.querySelectorAll('.cabinet__form')
   for (let i = 0; i < forms.length; i++) {
      const submit = forms[i].querySelector("button");
      submit.addEventListener('click', validate);
      function validate(e) {
         e.preventDefault();
         let blocks = forms[i].querySelectorAll('.cabinet__form-item')
         let valid = true;
         for (let a = 0; a < blocks.length; a++) {
            let input = blocks[a].querySelector("input");
            let result = blocks[a].querySelector('.cabinet__form-result')
            if (!input.value) {
               input.classList.add("invalid");
               result.classList.add('show')
            } else {
               input.classList.remove("invalid");
               result.classList.remove('show')
            }
         }
         return valid;
      }
   }
}
